import React from 'react';
import { Box, Typography, Paper, Avatar, Container } from '@mui/material';
import Contact from '../components/Contact';

const Home = () => {
  // Example: Replace with dynamic photo URL from admin profile in the future
  const photoUrl = '/profile-photo.jpg';
  return (
    <Box>
      {/* Hero Section */}
      <Paper
        sx={{
          position: 'relative',
          backgroundColor: 'grey.900',
          color: '#fff',
          mb: 4,
          backgroundSize: 'cover',
          backgroundRepeat: 'no-repeat',
          backgroundPosition: 'center',
          backgroundImage: 'linear-gradient(120deg, #232526 0%, #414345 100%)',
          height: { xs: 'auto', md: '60vh' },
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexDirection: 'column',
          boxShadow: 6,
          borderRadius: 4,
          p: 4
        }}
      >
        <Avatar
          src={photoUrl}
          alt="Profile Photo"
          sx={{ width: 140, height: 140, mb: 3, boxShadow: 3, border: '4px solid #fff' }}
        />
        <Typography
          component="h1"
          variant="h3"
          color="inherit"
          gutterBottom
          align="center"
          sx={{ fontWeight: 700, letterSpacing: 1 }}
        >
          Abdulhadi Akanni
        </Typography>
        <Typography variant="h5" color="inherit" paragraph align="center" sx={{ mb: 2 }}>
          Full Stack Developer | Machine Learning Enthusiast | Problem Solver
        </Typography>
        <Typography variant="body1" color="#e0e0e0" align="center" sx={{ maxWidth: 600, mx: 'auto' }}>
          Welcome to my professional portfolio. Explore my work, skills, and experience. Let's connect and build something great together!
        </Typography>
      </Paper>
      {/* Contact Section */}
      <Container maxWidth="md" sx={{ my: 6 }}>
        <Typography variant="h4" gutterBottom align="center" sx={{ fontWeight: 600 }}>
          Contact Me
        </Typography>
        <Contact />
      </Container>
    </Box>
  );
};

export default Home;
